-- First, update the onboarding_drills table to include all new fields
ALTER TABLE public.onboarding_drills
ADD COLUMN IF NOT EXISTS when_to_use text,
ADD COLUMN IF NOT EXISTS setup text,
ADD COLUMN IF NOT EXISTS steps jsonb DEFAULT '[]'::jsonb,
ADD COLUMN IF NOT EXISTS reps integer,
ADD COLUMN IF NOT EXISTS script_snippets jsonb DEFAULT '[]'::jsonb,
ADD COLUMN IF NOT EXISTS success_criteria jsonb DEFAULT '[]'::jsonb,
ADD COLUMN IF NOT EXISTS common_mistakes jsonb DEFAULT '[]'::jsonb,
ADD COLUMN IF NOT EXISTS variants jsonb DEFAULT '[]'::jsonb;

-- Clear existing drills
DELETE FROM public.onboarding_drills;

