('OPENING_TO_QUESTION', 'Åbning → første behovsspørgsmål', 'B', 6, 'Når sælger tøver i starten, virker nervøs, eller starter med pitch.', 'Når sælger tøver i starten, virker nervøs, eller starter med pitch.', 'Stå op eller sid ret. Smil i stemmen. Hav 1 behovsspørgsmål klar.', '["Sig: \"Hej, det er [navn] fra [virksomhed] – har jeg ringet på et okay tidspunkt?\"", "Vent 1 sekund (ingen fyldord).", "Sig: \"Super – må jeg stille dig et par hurtige spørgsmål?\"", "Stil ét behovsspørgsmål (vælg ét af dine scripts nedenfor).", "Hold en pause og lyt."]'::jsonb, 15, '["Hvordan gør I det i dag?", "Hvad bruger I typisk på [område]?", "Hvad er vigtigst for jer, når det kommer til [X]?"]'::jsonb, '["15 gentagelser uden at snuble", "Du går ikke direkte til pitch", "Du holder pause efter spørgsmålet"]'::jsonb, '["Undskylder for opkaldet", "Taler for længe før første spørgsmål", "Fylder stilhed ud"]'::jsonb, '["solo", "manager-led"]'::jsonb),

('STRUCTURED_OPENING', 'Struktureret åbning (ramme på 15 sek)', 'Struktur', 6, 'Når samtaler starter rodet eller sælger mister kontrol tidligt.', 'Når samtaler starter rodet eller sælger mister kontrol tidligt.', 'Hav ''årsag'' klar i én sætning.', '["Sig åbningen højt som én kort blok:", "\"Jeg ringer kort fordi [årsag]. Det tager 2 minutter, og hvis det ikke er relevant, stopper vi bare – okay?\"", "Hold 1 sekund pause.", "Gentag igen med ny ''årsag''."]'::jsonb, 10, '["Jeg ringer kort fordi vi hjælper med [outcome]. Det tager 2 minutter, og hvis det ikke er relevant, stopper vi bare – okay?"]'::jsonb, '["Åbningen er kort og rolig", "Ingen undskyldning / overforklaring"]'::jsonb, '["Bliver for lang", "Lyder usikker: \"øh, jeg ved godt...\""]'::jsonb, '["solo", "buddy", "manager-led"]'::jsonb),

('QUESTION_LADDER', 'Spørgestigen (åbent → konkret → konsekvens)', 'B', 8, 'Når behovet bliver for overfladisk, eller sælger ikke får noget at bygge løsning på.', 'Når behovet bliver for overfladisk, eller sælger ikke får noget at bygge løsning på.', 'Vælg et emne/produktområde og 1 kundetype.', '["Åbent spørgsmål: \"Hvordan gør I det i dag?\"", "Konkret opfølgning: \"Hvor ofte oplever I det?\"", "Konsekvens: \"Hvad betyder det for jer i hverdagen?\"", "Stop – lyt – skriv 3 nøgleord ned."]'::jsonb, 10, '["Hvordan gør I det i dag?", "Hvor ofte oplever I det?", "Hvad betyder det for jer i hverdagen?"]'::jsonb, '["Du når konsekvensspørgsmålet hver gang", "Du lytter uden at afbryde"]'::jsonb, '["Springer direkte til løsning", "Stiller 5 spørgsmål uden at lytte"]'::jsonb, '["solo", "manager-led"]'::jsonb),

